template<class T, class U>
struct traits_asval<std::pair<T, U>> {
  typedef std::pair<T, U> value_type;

  static int get_pair(VALUE first, VALUE second, std::pair<T, U>* val) {
    if (val) {
      T*  pfirst = &(val->first);
      int res1   = swig::asval((VALUE)first, pfirst);
      if (!SWIG_IsOK(res1))
        return res1;
      U*  psecond = &(val->second);
      int res2    = swig::asval((VALUE)second, psecond);
      if (!SWIG_IsOK(res2))
        return res2;
      return res1 > res2 ? res1 : res2;
    } else {
      T*  pfirst = 0;
      int res1   = swig::asval((VALUE)first, pfirst);
      if (!SWIG_IsOK(res1))
        return res1;
      U*  psecond = 0;
      int res2    = swig::asval((VALUE)second, psecond);
      if (!SWIG_IsOK(res2))
        return res2;
      return res1 > res2 ? res1 : res2;
    }
  }

  static int asval(VALUE obj, std::pair<T, U>* val) {
    int res = SWIG_ERROR;
    if (TYPE(obj) == T_ARRAY) {
      if (RARRAY_LEN(obj) == 2) {
        VALUE first  = rb_ary_entry(obj, 0);
        VALUE second = rb_ary_entry(obj, 1);
        res          = get_pair(first, second, val);
      }
    } else {
      value_type*     p;
      swig_type_info* descriptor = swig::type_info<value_type>();
      res = descriptor ? SWIG_ConvertPtr(obj, (void**)&p, descriptor, 0) : SWIG_ERROR;
      if (SWIG_IsOK(res) && val)
        *val = *p;
    }
    return res;
  }
};

template<class T, class U>
struct traits_asptr<std::pair<T, U>> {
  typedef std::pair<T, U> value_type;

  static int get_pair(VALUE first, VALUE second, std::pair<T, U>** val) {
    if (val) {
      value_type* vp     = (new std::pair<T, U>());
      T*          pfirst = &(vp->first);
      int         res1   = swig::asval((VALUE)first, pfirst);
      if (!SWIG_IsOK(res1)) {
        delete vp;
        return res1;
      }
      U*  psecond = &(vp->second);
      int res2    = swig::asval((VALUE)second, psecond);
      if (!SWIG_IsOK(res2)) {
        delete vp;
        return res2;
      }
      *val = vp;
      return SWIG_AddNewMask(res1 > res2 ? res1 : res2);
    } else {
      T*  pfirst = 0;
      int res1   = swig::asval((VALUE)first, pfirst);
      if (!SWIG_IsOK(res1))
        return res1;
      U*  psecond = 0;
      int res2    = swig::asval((VALUE)second, psecond);
      if (!SWIG_IsOK(res2))
        return res2;
      return res1 > res2 ? res1 : res2;
    }
  }

  static int asptr(VALUE obj, std::pair<T, U>** val) {
    int res = SWIG_ERROR;
    if (TYPE(obj) == T_ARRAY) {
      if (RARRAY_LEN(obj) == 2) {
        VALUE first  = rb_ary_entry(obj, 0);
        VALUE second = rb_ary_entry(obj, 1);
        res          = get_pair(first, second, val);
      }
    } else {
      value_type*     p;
      swig_type_info* descriptor = swig::type_info<value_type>();
      res = descriptor ? SWIG_ConvertPtr(obj, (void**)&p, descriptor, 0) : SWIG_ERROR;
      if (SWIG_IsOK(res) && val)
        *val = p;
    }
    return res;
  }
};

template<class T, class U>
struct traits_from<std::pair<T, U>> {
  static VALUE _wrap_pair_second(VALUE self) {
    std::pair<typename swig::noconst_traits<T>::noconst_type, U>* p = NULL;
    swig::asptr(self, &p);
    return swig::from(p->second);
  }

  static VALUE _wrap_pair_second_eq(VALUE self, VALUE arg) {
    std::pair<typename swig::noconst_traits<T>::noconst_type, U>* p = NULL;
    swig::asptr(self, &p);
    return swig::from(p->second);
  }

  static VALUE from(const std::pair<T, U>& val) {
    VALUE obj = rb_ary_new2(2);
    rb_ary_push(obj, swig::from<typename swig::noconst_traits<T>::noconst_type>(val.first));
    rb_ary_push(obj, swig::from(val.second));
    rb_define_singleton_method(obj, "second", VALUEFUNC(_wrap_pair_second), 0);
    rb_define_singleton_method(obj, "second=", VALUEFUNC(_wrap_pair_second_eq), 1);
    rb_obj_freeze(obj); // treat as immutable tuple
    return obj;
  }
};

